        val xmlFile = File("src/main/res/xml/preferences_controls.xml")
        assertTrue(xmlFile.exists())
        val content = xmlFile.readText()

        // Match PreferenceCategory blocks using (?s) for dot-all mode
        val categoryRegex = Regex("(?s)<PreferenceCategory\\s+[^>]*android:key=\"([^\"]+)\"[^>]*>(.*?)</PreferenceCategory>")
