            val categoryMatch = categoryMatches.find { it.groupValues[1] == expectedCategoryKey }
            assertTrue("Category $expectedCategoryKey not found in XML", categoryMatch != null)

            val categoryContent = categoryMatch!!.groupValues[2]
            assertTrue("Command ${command.name} not found in category $expectedCategoryKey",
                categoryContent.contains("android:key=\"${command.preferenceKey}\""))
